package com.establo.controller;
import com.establo.dto.NotificationDto;import com.establo.service.NotificationService;import lombok.RequiredArgsConstructor;import org.springframework.http.HttpStatus;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/notifications") @RequiredArgsConstructor public class NotificationController {private final NotificationService service;@GetMapping List<NotificationDto> all(){return service.all();}@GetMapping("/unread-count") Map<String,Long> unread(){return Map.of("count",service.unread());}@PatchMapping("/{id}/read") NotificationDto read(@PathVariable Long id){return service.markRead(id);}@PatchMapping("/read-all") @ResponseStatus(HttpStatus.NO_CONTENT) void readAll(){service.markAllRead();}}
